class Solution {
    public int[] smallestTrimmedNumbers(String[] nums, int[][] queries) {
        int[] answer = new int[queries.length];
        for (int i = 0; i < queries.length; i++) {
            int k = queries[i][0];
            int trim = queries[i][1];
            String[] trimmedNums = new String[nums.length];
            for (int j = 0; j < nums.length; j++) {
                trimmedNums[j] = nums[j].substring(nums[j].length() - trim);
            }
            Arrays.sort(trimmedNums);
            answer[i] = Arrays.binarySearch(trimmedNums, trimmedNums[k - 1]) + 1;
            for (int j = 0; j < nums.length; j++) {
                nums[j] = nums[j].substring(0, nums[j].length() - trim);
            }
        }
        return answer;
    }
}
